import { SeedApiClient } from "../../src/Client";
import { mockServerPool } from "../mock-server/MockServerPool";

describe("HeadersClient", () => {
    test("send", async () => {
        const server = mockServerPool.createServer();
        const client = new SeedApiClient({ maxRetries: 0, environment: server.baseUrl });
        const rawRequestBody = { query: "query" };
        const rawResponseBody = { message: "message", status: 1, success: true };

        server
            .mockEndpoint()
            .post("/headers")
            .header("X-Endpoint-Version", "02-12-2024")
            .header("X-Async", "true")
            .jsonBody(rawRequestBody)
            .respondWith()
            .statusCode(200)
            .jsonBody(rawResponseBody)
            .build();

        const response = await client.headers.send({
            "X-Endpoint-Version": "02-12-2024",
            "X-Async": true,
            query: "query",
        });
        expect(response).toEqual(rawResponseBody);
    });
});
